import React, { Component } from 'react'
import MenuItem from '../components/MenuItem'

import me from '../img/me.jpg'

export default class Menu extends Component {
    state = {
        active: [true,false,false,false,false,false,false,false],
        menuActive: false
    }

    toggleMenu() {
        console.log('click');
        this.setState({menuActive: !this.state.menuActive})
    }

    componentDidMount() {
        if(window.innerWidth >= 640) {
            this.setState({menuActive: true })
        }
    }

    componentDidUpdate(prevProps){
        if(prevProps.active !== this.props.active){
            let arr = [false,false,false,false,false,false,false,false]
            arr[this.props.active] = true;
            this.setState({active: arr})
        }
    }

    render() {
        return (
            <>
                <div className="fixed md:hidden top-0 w-full z-10 pb-1 shadow-2xl" style={{ background: "linear-gradient(90deg,#184669,#F9F871)" }}>
                    <div className="bg-white h-full w-full p-5 text-center">
                        <i onClick={() => this.toggleMenu()} class="fas fa-bars text-3xl left inline-block float-left align-middle px-3" style={{ color: "#184669" }}></i>
                        <p className="text-3xl inline-block align-middle -ml-5" style={{ color: "#184669" }}>Daniel Melchor</p>
                    </div>
                </div>
                <div
                    className="w-5/6 shadow-2xl fixed md:w-1/4 lg:w-1/5 xl:w-1/6 h-screen z-50 bg-white"
                    style={ this.state.menuActive ? {display: "block"} : {display: "none"} }
                >
                    <div className="w-full py-5 flex flex-wrap items-center justify-center hidden md:block">
                        <div className="rounded-full m-auto p-1 w-1/2 my-2" style={{ background: "linear-gradient(90deg,#184669,#F9F871)" }}><img className="rounded-full block" src={me} alt=""/></div>
                        <p className="text-3xl w-full text-center" style={{ color: "#184669" }}>Daniel Melchor</p>
                    </div>
                    <div className="h-1 w-full" style={{ background: "linear-gradient(90deg,#184669,#F9F871)" }}></div>
                    <div className="pt-5">
                        <i onClick={() => this.toggleMenu()} class="md:hidden z-20 fas fa-times text-3xl w-full text-right mb-2 block px-3" style={{ color: "#184669" }}></i>
                        <MenuItem text="Welcome" color="#184669" icon="fab fa-creative-commons-zero" linkTo="#welcome" activeNow={this.state.active[0]} />
                        <MenuItem text="About" color="#385f6a" icon="fas fa-user" linkTo="#about" activeNow={this.state.active[1]} />
                        <MenuItem text="Experience" color="#57786b" icon="fas fa-user-tie" linkTo="#experience" activeNow={this.state.active[2]} />
                        <MenuItem text="Projects" color="#79936c" icon="fas fa-tools" linkTo="#projects" activeNow={this.state.active[3]} />
                        <MenuItem text="Skills" color="#98ac6d" icon="fas fa-chart-bar" linkTo="#skills" activeNow={this.state.active[4]} />
                        <MenuItem text="Education" color="#b8c56e" icon="fas fa-graduation-cap" linkTo="#education" activeNow={this.state.active[5]} />
                        <MenuItem text="Contact" color="#d7de6f" icon="fas fa-comment-dots" linkTo="#contact" activeNow={this.state.active[6]} />
                        <MenuItem text="Resume" color="#d5d461" icon="fas fa-file" linkTo="#resume" activeNow={this.state.active[7]} />
                    </div>
                </div>
            </>
        )
    }
}
